//vip.opstream14.com/20221217/28573_8fbe90bc/index.m3u8"}]}],"time":"96 phút","description":"<p>Azura là người cuối cùng của Sarnians, một chủng tộc chiến binh đáng sợ. Thế giới nhà của cô, từng là một thiên đường xinh đẹp, giờ đây là một con trấn vô hồn sau khi Visrary phá hủy nó trong thời thơ ấu của cô. Cô sống sót và sống lang thang trên các đường phố của Draiga, lớn lên để lãnh đạo một nhóm chiến binh kháng chiến chống lại chế độ tà ác của Bộ Tư Lệnh Mục Triết Diện Sorrentine.</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2022-12-18T11:03:13.000Z"},{"id":"639e91417fe60587644b3090","_id":"639e91417fe60587644b3090","title":"Kẻ Ám Sát Từ Phía Sau","origin_name":"Kẻ Ám Sát Từ Phía Sau","slug":"ke-am-sat-tu-phia-sau","year":2018,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Thuyết Minh #1","server_data":[{"name":"Full","slug":"full","filename":"Kẻ Ám Sát Từ Phía Sau","link_embed":"https://vip.opstream14.com/share/2def82558a0b5b01ac62b2bc46cfdb76","link_m3u8":"https://vip.opstream14.com/20221217/28577_0b3fa6d6/index.m3u8"}]}],"time":"84 phút","description":"<p>Skye - tác giả có cuốn sách bán chạy nhất đã không thể viết gì kể từ hit của cô cách đây vài năm, túng thiếu, cô chấp nhận công việc tư vấn cho Holly một nhà văn trẻ cũng là fan hâm mộ để kiếm thêm thu nhập, nhưng lòng tham và danh tiếng đã khiến cô mờ mắt, ăn cắp tác phẩm của Holly và tự nhận với nhà xuất bản do mình sáng tác. Skye